fn solve(digitSum: Vec<i64>) -> i64 {
    let MOD: i64 = 1_000_000_007;
    let V_MAX: usize = 5000;

    // Helper function to calculate the sum of digits
    let digit_sum = |mut n: i64| -> i64 {
        let mut sum = 0;
        if n == 0 {
            return 0;
        }
        while n > 0 {
            sum += (n % 10) as i64;
            n /= 10;
        }
        sum
    };

    let N = digitSum.len();

    // dp_prev[v] stores the number of ways to form a valid prefix ending in v at the previous step.
    // Size is V_MAX + 1 for indices 0 to 5000.
    let mut dp_prev = vec![0i64; V_MAX + 1];

    // --- Initialization (i = 0) ---
    let target_sum_0 = digitSum[0];
    for v in 0..=V_MAX as i64 {
        if digit_sum(v) == target_sum_0 {
            dp_prev[v as usize] = 1;
        }
    }

    // --- DP Transition (i = 1 to N-1) ---
    for i in 1..N {
        let target_sum_current = digitSum[i];
        let target_sum_prev = digitSum[i-1];

        let mut dp_curr = vec![0i64; V_MAX + 1];

        // 1. Calculate Prefix Sum P for the previous state (i-1)
        // P[v] = sum(dp_prev[u]) for u <= v, provided digit_sum(u) == target_sum_prev
        let mut prefix_sum_prev = vec![0i64; V_MAX + 1];

        for v in 0..=V_MAX {
            let mut current_sum = prefix_sum_prev[v - 1]; // Safe access if v=0, prefix_sum_prev[-1] is conceptually 0
            if v > 0 {
                current_sum = prefix_sum_prev[v - 1];
            }

            if digit_sum(v as i64) == target_sum_prev {
                current_sum = (current_sum + dp_prev[v]) % MOD;
            }
            prefix_sum_prev[v] = current_sum;
        }

        // 2. Calculate current DP state (i)
        for v in 0..=V_MAX {
            if digit_sum(v as i64) == target_sum_current {
                // DP[i][v] = Sum of DP[i-1][u] for u <= v and satisfying constraints.
                // This sum is exactly prefix_sum_prev[v].
                dp_curr[v] = prefix_sum_prev[v];
            }
            // else: dp_curr[v] remains 0
        }

        dp_prev = dp_curr;
    }

    // --- Final Result ---
    let mut total_count = 0i64;
    for count in dp_prev.iter() {
        total_count = (total_count + *count) % MOD;
    }

    total_count
}

