const MOD = 10**9 + 7;

/**
 * Calculates the sum of digits of a non-negative integer n.
 * @param {number} n
 * @returns {number}
 */
function getDigitSum(n) {
    let sum = 0;
    let s = String(n);
    for (let i = 0; i < s.length; i++) {
        sum += parseInt(s[i]);
    }
    return sum;
}

/**
 * Finds all numbers x in [0, 5000] such that the sum of digits of x equals targetSum.
 * @param {number} targetSum
 * @returns {number[]} Sorted array of numbers.
 */
function precalculateValidNumbers(targetSum) {
    const valid = [];
    // Iterate up to 5000 inclusive
    for (let x = 0; x <= 5000; x++) {
        if (getDigitSum(x) === targetSum) {
            valid.push(x);
        }
    }
    // The loop ensures they are already sorted, but explicit sort doesn't hurt
    return valid;
}

/**
 * Finds the index of the last element in a sorted array 'arr' that is less than or equal to 'target'.
 * Returns -1 if all elements are greater than 'target'.
 * This is equivalent to finding the count of elements <= target.
 * @param {number[]} arr - Sorted array of numbers.
 * @param {number} target
 * @returns {number} The index (0-based) of the last element <= target.
 */
function binarySearchLastLE(arr, target) {
    let low = 0;
    let high = arr.length - 1;
    let resultIndex = -1;

    while (low <= high) {
        const mid = Math.floor((low + high) / 2);
        if (arr[mid] <= target) {
            resultIndex = mid;
            low = mid + 1; // Try to find a larger index
        } else {
            high = mid - 1; // Too large
        }
    }
    return resultIndex;
}


function solve(digitSum) {
    const N = digitSum.length;

    // 1. Precalculate all necessary valid number sets V_D
    // Since max digit sum is 50, we precalculate up to 50.
    const MaxD = 50;
    const ValidNumbersCache = new Array(MaxD + 1).fill(null);

    for (let D = 0; D <= MaxD; D++) {
        ValidNumbersCache[D] = precalculateValidNumbers(D);
    }

    // 2. Dynamic Programming setup

    // dp_prev[j] stores the count of valid sequences ending with V_{i-1}[j]
    let dp_prev = []; 

    // --- Base Case i = 0 ---
    const V0 = ValidNumbersCache[digitSum[0]];
    if (V0.length === 0) {
        return 0; // No valid number for the first element
    }

    dp_prev = new Array(V0.length).fill(1);

    // --- Transitions i = 1 to N-1 ---
    for (let i = 1; i < N; i++) {
        const Di = digitSum[i];
        const Di_1 = digitSum[i-1];

        const Vi = ValidNumbersCache[Di];
        const Vi_1 = ValidNumbersCache[Di_1];

        if (Vi.length === 0) {
            return 0; // No valid number for the current element
        }

        const Ki = Vi.length;
        const Ki_1 = Vi_1.length;

        // Calculate prefix sums for dp_prev (based on V_{i-1})
        // P[k] = sum(dp_prev[0] + ... + dp_prev[k])
        const P_prev = new Array(Ki_1).fill(0);
        let currentSum = 0;
        for (let k = 0; k < Ki_1; k++) {
            currentSum = (currentSum + dp_prev[k]) % MOD;
            P_prev[k] = currentSum;
        }

        const dp_curr = new Array(Ki).fill(0);

        // Calculate dp_curr[j] for a_i = Vi[j]
        for (let j = 0; j < Ki; j++) {
            const current_val = Vi[j];

            // Find the count of numbers in Vi_1 that are <= current_val
            // This corresponds to finding the largest index k_max such that Vi_1[k_max] <= current_val
            const k_max_index = binarySearchLastLE(Vi_1, current_val);

            if (k_max_index === -1) {
                // No previous number is <= current_val, so the count is 0
                dp_curr[j] = 0;
            } else {
                // The sum of counts up to index k_max_index in P_prev
                dp_curr[j] = P_prev[k_max_index];
            }
        }

        // Update for the next iteration
        dp_prev = dp_curr;
    }

    // 3. Final Result
    let totalCount = 0;
    for (let count of dp_prev) {
        totalCount = (totalCount + count) % MOD;
    }

    return totalCount;
}
