 * Returns -1 if all elements are greater than 'target'.
 * This is equivalent to finding the count of elements <= target.
 * @param {number[]} arr - Sorted array of numbers.
 * @param {number} target
 * @returns {number} The index (0-based) of the last element <= target.
 */
function binarySearchLastLE(arr, target) {
    let low = 0;
    let high = arr.length - 1;
    let resultIndex = -1;

    while (low <= high) {
        const mid = Math.floor((low + high) / 2);
        if (arr[mid] <= target) {
            resultIndex = mid;
            low = mid + 1; // Try to find a larger index
        } else {
            high = mid - 1; // Too large
        }
    }
    return resultIndex;
}


